namespace BogDb.Core.Common;

/// <summary>
/// Mirrors the LogicalTypeUtils from BogDb C++.
/// Contains static methods for querying the semantic properties of BogDb's type system.
/// </summary>
public static class LogicalTypeUtils
{
    public static bool IsDate(LogicalTypeID dataType)
    {
        return dataType == LogicalTypeID.DATE;
    }

    public static bool IsTimestamp(LogicalTypeID dataType)
    {
        return dataType == LogicalTypeID.TIMESTAMP ||
               dataType == LogicalTypeID.TIMESTAMP_SEC ||
               dataType == LogicalTypeID.TIMESTAMP_MS ||
               dataType == LogicalTypeID.TIMESTAMP_NS ||
               dataType == LogicalTypeID.TIMESTAMP_TZ;
    }

    public static bool IsUnsigned(LogicalTypeID dataType)
    {
        return dataType == LogicalTypeID.UINT64 ||
               dataType == LogicalTypeID.UINT32 ||
               dataType == LogicalTypeID.UINT16 ||
               dataType == LogicalTypeID.UINT8 ||
               dataType == LogicalTypeID.UINT128;
    }

    public static bool IsIntegral(LogicalTypeID dataType)
    {
        return dataType == LogicalTypeID.INT64 ||
               dataType == LogicalTypeID.INT32 ||
               dataType == LogicalTypeID.INT16 ||
               dataType == LogicalTypeID.INT8 ||
               dataType == LogicalTypeID.INT128 ||
               IsUnsigned(dataType);
    }

    public static bool IsFloatingPoint(LogicalTypeID dataType)
    {
        return dataType == LogicalTypeID.DOUBLE ||
               dataType == LogicalTypeID.FLOAT;
    }

    public static bool IsNumerical(LogicalTypeID dataType)
    {
        return IsIntegral(dataType) || IsFloatingPoint(dataType) || dataType == LogicalTypeID.DECIMAL;
    }

    public static bool IsNested(LogicalTypeID dataType)
    {
        return dataType == LogicalTypeID.LIST ||
               dataType == LogicalTypeID.ARRAY ||
               dataType == LogicalTypeID.STRUCT ||
               dataType == LogicalTypeID.MAP ||
               dataType == LogicalTypeID.UNION;
    }

    public static PhysicalTypeID GetPhysicalType(LogicalTypeID logicalTypeID)
    {
        switch (logicalTypeID)
        {
            case LogicalTypeID.ANY: return PhysicalTypeID.ANY;
            case LogicalTypeID.BOOL: return PhysicalTypeID.BOOL;
            case LogicalTypeID.INT64: return PhysicalTypeID.INT64;
