            case LogicalTypeID.INT16: return PhysicalTypeID.INT16;
            case LogicalTypeID.INT8: return PhysicalTypeID.INT8;
            case LogicalTypeID.UINT64: return PhysicalTypeID.UINT64;
            case LogicalTypeID.UINT32: return PhysicalTypeID.UINT32;
            case LogicalTypeID.UINT16: return PhysicalTypeID.UINT16;
            case LogicalTypeID.UINT8: return PhysicalTypeID.UINT8;
            case LogicalTypeID.INT128: return PhysicalTypeID.INT128;
            case LogicalTypeID.UINT128: return PhysicalTypeID.UINT128;
            case LogicalTypeID.DOUBLE: return PhysicalTypeID.DOUBLE;
            case LogicalTypeID.FLOAT: return PhysicalTypeID.FLOAT;
            case LogicalTypeID.DATE: return PhysicalTypeID.INT32;
            case LogicalTypeID.TIMESTAMP: return PhysicalTypeID.INT64;
            case LogicalTypeID.TIMESTAMP_SEC: return PhysicalTypeID.INT64;
            case LogicalTypeID.TIMESTAMP_MS: return PhysicalTypeID.INT64;
            case LogicalTypeID.TIMESTAMP_NS: return PhysicalTypeID.INT64;
            case LogicalTypeID.TIMESTAMP_TZ: return PhysicalTypeID.INT64;
            case LogicalTypeID.INTERVAL: return PhysicalTypeID.INTERVAL;
            case LogicalTypeID.INTERNAL_ID: return PhysicalTypeID.INTERNAL_ID;
            case LogicalTypeID.STRING: return PhysicalTypeID.STRING;
            case LogicalTypeID.BLOB: return PhysicalTypeID.STRING;
            case LogicalTypeID.LIST: return PhysicalTypeID.LIST;
            case LogicalTypeID.ARRAY: return PhysicalTypeID.ARRAY;
            case LogicalTypeID.STRUCT: return PhysicalTypeID.STRUCT;
            case LogicalTypeID.NODE: return PhysicalTypeID.STRUCT;
            case LogicalTypeID.REL: return PhysicalTypeID.STRUCT;
            case LogicalTypeID.RECURSIVE_REL: return PhysicalTypeID.STRUCT;
            case LogicalTypeID.MAP: return PhysicalTypeID.LIST;
            case LogicalTypeID.UNION: return PhysicalTypeID.STRUCT;
            case LogicalTypeID.POINTER: return PhysicalTypeID.POINTER;
