    public static uint GetFixedTypeSize(PhysicalTypeID physicalType)
    {
        switch (physicalType)
        {
            case PhysicalTypeID.ANY:
                return 16;
            case PhysicalTypeID.BOOL:
                return 1;
            case PhysicalTypeID.INT64:
            case PhysicalTypeID.UINT64:
            case PhysicalTypeID.DOUBLE:
            case PhysicalTypeID.INTERVAL:
                return 8;
            case PhysicalTypeID.INT32:
            case PhysicalTypeID.UINT32:
            case PhysicalTypeID.FLOAT:
                return 4;
            case PhysicalTypeID.INT16:
            case PhysicalTypeID.UINT16:
                return 2;
            case PhysicalTypeID.INT8:
            case PhysicalTypeID.UINT8:
                return 1;
            case PhysicalTypeID.INT128:
            case PhysicalTypeID.UINT128:
                return 16;
            case PhysicalTypeID.INTERNAL_ID:
                return 16;
            case PhysicalTypeID.STRING:
                return 16; // mapped to ku_string_t size
            case PhysicalTypeID.LIST:
                return 12; // mapped to list_entry_t size
            case PhysicalTypeID.ARRAY:
                return 12; // list_entry_t-compatible in current C# storage path
            case PhysicalTypeID.STRUCT:
            case PhysicalTypeID.POINTER:
                return 8; // pointer/reference-sized slot for nested payload indirection
            default:
                throw new NotSupportedException($"Cannot get fixed size for physical type ID: {physicalType}");
        }
    }
